mapper.select:
select value , label from (

    select distinct SECONDARYORGANIZATIONCH as value , SECONDARYORGANIZATIONCH as label
    from CLASSIFY_INTERFACE_ALL_DATE where PRIMARYORGANIZATIONCH = #{firstClassValue}
    and  SECONDARYORGANIZATIONCH is not null and SJXJBM is not null


    select distinct SECONDARYDATASOURCECH as value ,SECONDARYDATASOURCECH as label
    from CLASSIFY_INTERFACE_ALL_DATE where PRIMARYDATASOURCECH =#{firstClassValue}
    and SECONDARYDATASOURCECH is not null and SJXJBM is not null


    select distinct FACTORTWONAME as value , FACTORTWONAME as label
    from CLASSIFY_INTERFACE_ALL_DATE where FACTORONENAME =#{firstClassValue}
    and FACTORTWONAME is not null and SJXJBM is not null

) t1

select distinct tablename from CLASSIFY_INTERFACE_ALL_DATE

    sjxjbm is not null

        and  PRIMARYORGANIZATIONCH = #{firstValue}


        and SECONDARYORGANIZATIONCH = #{secondaryClassifyValue}


        and THREEORGANIZATIONCH = #{threeClassifyValue}


        and upper(tablename) LIKE upper('%'||#{condition}||'%')

select code_text as label,code_value as value from ALL_CODE_DATA
where code_id = 'SECURITYLEVEL'

    and id = #{codeId}
